CREATE TABLE users (
  id SERIAL PRIMARY KEY,  -- auto-incrementa: 1, 2, 3, 4...
  name TEXT NOT NULL,
  email TEXT UNIQUE NOT NULL
);

-- Ahora cada usuario tiene un ID unico garantizado
INSERT INTO users (name, email) VALUES ('Alice', 'alice@mail.com');
-- el id se asigna automaticamente a 1
INSERT INTO users (name, email) VALUES ('Alice', 'alice2@mail.com');
-- el id se asigna automaticamente a 2 (otra Alice, sin confusion!)
